import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { apiFetch } from '../api';
import SearchBar from '../components/SearchBar.js';
import './css/Recipes.css';

const CUISINE_EMOJI = {
  italian: '🍝', mexican: '🌮', japanese: '🍱', chinese: '🥡',
  indian: '🍛', american: '🍔', french: '🥐', thai: '🍜',
  mediterranean: '🫒', greek: '🫙', default: '🍽',
};

function cuisineEmoji(cuisine) {
  if (!cuisine) return CUISINE_EMOJI.default;
  return CUISINE_EMOJI[cuisine.toLowerCase()] || CUISINE_EMOJI.default;
}

function Recipes({ user }) {
  const [recipes, setRecipes] = useState([]);
  const [filteredRecipes, setFilteredRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchRecipes = async () => {
      if (!user) { setLoading(false); return; }
      setLoading(true);
      try {
        const response = await apiFetch(`/recipes/user/${user.id || user._id}`);
        if (response.ok) {
          const data = await response.json();
          setRecipes(data);
          setFilteredRecipes(data);
        }
      } catch (err) {}
      setLoading(false);
    };
    fetchRecipes();
  }, [user]);

  const handleSearch = (query) => {
    setFilteredRecipes(
      recipes.filter((r) => r.recipe_name.toLowerCase().includes(query.toLowerCase()))
    );
  };

  if (!user) {
    return (
      <div className="page">
        <div className="recipes-auth-prompt">
          <h2>Your recipes, all in one place</h2>
          <p>Sign in to view and manage your recipe collection.</p>
          <Link to="/login" className="btn-primary" style={{ display: 'inline-flex' }}>
            Sign in
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="page">
      <div className="page-header">
        <h1>Recipes</h1>
        <button className="btn-primary" onClick={() => navigate('/recipes/add')}>
          + Add Recipe
        </button>
      </div>

      <div className="recipes-search">
        <SearchBar onSearch={handleSearch} />
      </div>

      <div className="recipe-grid">
        {loading ? (
          <p style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>Loading...</p>
        ) : filteredRecipes.length === 0 ? (
          <div className="recipes-empty">
            <div className="recipes-empty-icon">🍽</div>
            <h3>{recipes.length === 0 ? 'No recipes yet' : 'No results'}</h3>
            <p>
              {recipes.length === 0
                ? 'Add your first recipe to get started.'
                : 'Try a different search term.'}
            </p>
            {recipes.length === 0 && (
              <button className="btn-primary" onClick={() => navigate('/recipes/add')}>
                + Add your first recipe
              </button>
            )}
          </div>
        ) : (
          filteredRecipes.map((recipe, idx) => (
            <div
              className="card recipe-card"
              key={recipe._id || recipe.id || idx}
              onClick={() => navigate(`/recipes/${recipe._id || recipe.id}`)}
            >
              <div className="recipe-card-img-wrap">
                {recipe.image_url
                  ? <img src={recipe.image_url} alt={recipe.recipe_name} />
                  : <div className="recipe-card-placeholder">{cuisineEmoji(recipe.cuisine)}</div>
                }
              </div>
              <div className="recipe-card-body">
                <div className="recipe-card-title">{recipe.recipe_name}</div>
                <div className="recipe-card-meta">
                  {recipe.cuisine && <span className="badge">{recipe.cuisine}</span>}
                  {recipe.tags && <span className="badge">{recipe.tags}</span>}
                </div>
                {(recipe.prep_time || recipe.cook_time || recipe.servings) && (
                  <div className="recipe-card-times">
                    {recipe.prep_time && <span>Prep {recipe.prep_time}m</span>}
                    {recipe.cook_time && <span>Cook {recipe.cook_time}m</span>}
                    {recipe.servings && <span>Serves {recipe.servings}</span>}
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default Recipes;
